import anthropic
import json


class PEASGuardedAgent:
    """
    An LLM agent that enforces PEAS constraints at runtime.
    - Only calls tools listed in actuators.
    - Logs sensor inputs and actuator outputs for performance auditing.
    - Reports performance score at end of session.
    """

    def __init__(self, peas: PEASDescription, tools: list[dict]):
        self.peas = peas
        self.client = anthropic.Anthropic()
        # Guard: only allow tools whose names are in the actuators list
        allowed_names = {
            t.lower().replace(" ", "_").split("(")[0]
            for t in peas.actuators
        }
        self.tools = [
            t for t in tools
            if any(word in t["name"].lower() for word in
                   " ".join(peas.actuators).lower().split())
        ]
        self.session_log: list[dict] = []

    def _log(self, kind: str, data: dict) -> None:
        self.session_log.append({"kind": kind, **data})

    def run(self, user_message: str) -> str:
        """Single-turn agent execution with PEAS logging."""
        self._log("sensor", {"type": "user_message", "content": user_message})

        messages = [{"role": "user", "content": user_message}]
        response = self.client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=self.tools,
            messages=messages,
        )

        result_text = ""
        for block in response.content:
            if hasattr(block, "text"):
                result_text = block.text
            elif block.type == "tool_use":
                self._log("actuator", {
                    "tool": block.name,
                    "input": block.input,
                })

        self._log("actuator", {"type": "text_response", "content": result_text})
        return result_text

    def performance_report(self, outcomes: list[dict],
                            measures: list) -> dict:
        """Compute performance scores across a set of outcomes."""
        scores = {}
        for m in measures:
            scores[m.name] = sum(m.evaluate(o) for o in outcomes) / len(outcomes)
        return scores
